// ================= ROUTEN =================
app.get("/auftraege", async (req, res) => {
  res.json(await Auftrag.find());
});

app.post("/auftraege", async (req, res) => {
  const neuerAuftrag = new Auftrag({
    ...req.body,
    status: "offen",
    zeit: new Date().toLocaleString("de-DE"),
  });
  await neuerAuftrag.save();
  await updateClients();
  res.json(neuerAuftrag);
});

// ================= PUT (VERBESSERT) =================
app.put("/auftraege/:id", async (req, res) => {
  try {
    const { lat, lng, fahrer, statusUpdate, bild } = req.body;
    let auftrag = await Auftrag.findById(req.params.id);
    if (!auftrag) return res.sendStatus(404);

    let emailSenden = false;

    // 1. Fahrer-Zuweisung
    if (fahrer !== undefined) {
      auftrag.fahrer = fahrer;
    }

    // 2. NEU: Archiv-Logik
    if (statusUpdate === "archiviert") {
      auftrag.status = "archiviert";
      console.log(`Auftrag ${auftrag.nummer} wurde archiviert`);
    }

    // 3. Reset-Logik (Status auf Offen setzen für 2. Versuch)
    if (statusUpdate === "reset") {
      auftrag.status = "offen";
      auftrag.zweiteAnfahrt = true;
    }

    // 4. Status-Update durch Fahrer
    if (statusUpdate === "fehlanfahrt") {
      emailSenden = true;
      
      // WICHTIG: In jedem Fall muss der Status auf "fehlanfahrt" gesetzt werden,
      // damit der Auftrag beim Fahrer aus der Liste "Meine Aufträge" verschwindet!
      auftrag.status = "fehlanfahrt"; 

      if (auftrag.fehlanfahrt && auftrag.fehlanfahrt.zeit) {
        // Es ist der zweite Versuch
        auftrag.fehlanfahrt2 = { zeit: new Date(), gps: { lat, lng }, bild };
      } else {
        // Es ist der erste Versuch
        auftrag.fehlanfahrt = { zeit: new Date(), gps: { lat, lng }, bild };
      }
    }
    else if (!statusUpdate && lat && lng) {
      // Normales "Erledigt"
      auftrag.status = "erledigt";
      auftrag.zeitErledigt = new Date();
      auftrag.gps = { lat, lng };
      emailSenden = true;
    }

    await auftrag.save();
    await updateClients();

    // 5. PDF GENERIERUNG & MAIL
    if (emailSenden) {
      const doc = new PDFDocument({ margin: 40 });
      const chunks = [];
      doc.on("data", (chunk) => chunks.push(chunk));

      doc.on("end", async () => {
        const pdfBuffer = Buffer.concat(chunks);
        const baseDate = auftrag.zeitErledigt || (auftrag.fehlanfahrt2 ? auftrag.fehlanfahrt2.zeit : auftrag.fehlanfahrt.zeit);
        
        const getKW = (date) => {
          const d = new Date(date);
          d.setDate(d.getDate() + 4 - (d.getDay() || 7));
          return Math.ceil(((d - new Date(d.getFullYear(), 0, 1)) / 86400000 + 1) / 7);
        };

        const fileName = `${baseDate.getFullYear()}_KW${getKW(baseDate)}_${auftrag.nummer}_${auftrag.status.toUpperCase()}.pdf`;

        await transporter.sendMail({
          from: process.env.MAIL_USER,
          to: process.env.MAIL_TO,
          subject: `${auftrag.status.toUpperCase()}: Auftrag ${auftrag.nummer}`,
          text: `Bericht für Nr. ${auftrag.nummer}.`,
          attachments: [{ filename: fileName, content: pdfBuffer }],
        });
      });

      // PDF LAYOUT
      doc.fontSize(20).text("AUFTRAGSBERICHT", 40, 40);
      const logoBase64 = "data:image/png;base64,"; // Dein Logo-String
      try {
        doc.image(Buffer.from(logoBase64.split(",")[1], "base64"), 400, 25, { width: 130 });
      } catch(e) {}
      
      doc.moveTo(40, 110).lineTo(550, 110).stroke();
      let yPos = 130;

      doc.fontSize(12).font("Helvetica-Bold").text("Auftragsdetails:", 40, yPos); yPos += 20;
      doc.font("Helvetica").fontSize(10).text(`Nummer: ${auftrag.nummer}`, 40, yPos); yPos += 15;
      doc.text(`Adresse: ${auftrag.strasse}, ${auftrag.plzOrt}`, 40, yPos); yPos += 15;
      doc.text(`Material: ${auftrag.material}`, 40, yPos); yPos += 30;

      const drawBlock = (title, data, isAlert) => {
        if (!data || !data.zeit) return;
        doc.fillColor(isAlert ? "red" : "black").font("Helvetica-Bold").fontSize(12).text(title, 40, yPos); yPos += 20;
        doc.fillColor("black").font("Helvetica").fontSize(10).text(`Zeit: ${new Date(data.zeit).toLocaleString("de-DE")}`, 40, yPos); yPos += 15;
        if (data.gps) doc.text(`GPS: ${data.gps.lat}, ${data.gps.lng}`, 40, yPos); yPos += 20;
        if (data.bild) {
          try { doc.image(Buffer.from(data.bild.split(",")[1], "base64"), 40, yPos, { fit: [200, 150] }); yPos += 160; } catch(e) {}
        }
        yPos += 20;
      };

      drawBlock("1. ANFAHRT (Fehlanfahrt)", auftrag.fehlanfahrt, true);
      drawBlock("2. ANFAHRT (Fehlanfahrt)", auftrag.fehlanfahrt2, true);
      if (auftrag.status === "erledigt") {
        drawBlock("ERFOLGREICHE ANFAHRT", { zeit: auftrag.zeitErledigt, gps: auftrag.gps }, false);
      }
      doc.end();
    }

    res.json(auftrag);
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: "Server Fehler" });
  }
});

app.delete("/auftraege/:id", async (req, res) => {
  await Auftrag.findByIdAndDelete(req.params.id);
  await updateClients();
  res.json({ success: true });
});

server.listen(PORT, "0.0.0.0", () => console.log(`🚀 Server läuft auf Port ${PORT}`));